module top_module(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] invalid_count;

always @ (posedge clk or negedge reset) begin
  if (!reset) begin
    invalid_count <= 4'b0000;
  end else begin
    invalid_count <= invalid_count + 4'b0001;
  end
end

assign count = invalid_count;

endmodule
